async function watchProgress(t,a){if(t.body&&t.headers){const c=t.body.getReader(),n=Number(t.headers.get("Content-Length"))||0;let e=0;const o=async()=>{let t;try{t=await c.read()}catch{return}t.done||((async t=>{e+=t?.length||0;t=Math.round(e/n*100);a(t)})(t.value),await o())};o()}}async function fetchBlob(t,e,a){const c=await fetch(t,a);if(400<=c.status)throw new Error(`Failed to fetch ${t}: ${c.status} (${c.statusText})`);return watchProgress(c.clone(),e),c.blob()}const Fetcher={fetchBlob:fetchBlob};export default Fetcher;